38	struct SyllabifyTask {
39	  const Code& code;
40	  const SyllableGraph& graph;
41	  size_t target_pos;
42	  function<void(SyllabifyTask* task,
43	                size_t depth,
44	                size_t current_pos,
45	                size_t next_pos)>
46	      push;
47	  function<void(SyllabifyTask* task, size_t depth)> pop;
48	};
49	
50	static bool syllabify_dfs(SyllabifyTask* task,
51	                          size_t depth,
52	                          size_t current_pos) {
53	  if (depth == task->code.size()) {
54	    return current_pos == task->target_pos;
55	  }
56	  SyllableId syllable_id = task->code.at(depth);
57	  auto z = task->graph.edges.find(current_pos);
58	  if (z == task->graph.edges.end())
59	    return false;
60	  // favor longer spellings
61	  for (const auto& y : boost::adaptors::reverse(z->second)) {
62	    size_t end_vertex_pos = y.first;
63	    if (end_vertex_pos > task->target_pos)
64	      continue;
65	    auto x = y.second.find(syllable_id);
66	    if (x != y.second.end()) {
67	      task->push(task, depth, current_pos, end_vertex_pos);
68	      if (syllabify_dfs(task, depth + 1, end_vertex_pos))
69	        return true;
70	      task->pop(task, depth);
71	    }
72	  }
73	  return false;
74	}
