180	// ScriptTranslator implementation
181	
182	ScriptTranslator::ScriptTranslator(const Ticket& ticket)
183	    : Translator(ticket), Memory(ticket), TranslatorOptions(ticket) {
184	  if (!engine_)
185	    return;
186	  if (Config* config = engine_->schema()->config()) {
187	    config->GetInt(name_space_ + "/spelling_hints", &spelling_hints_);
188	    config->GetInt(name_space_ + "/max_word_length", &max_word_length_);
189	    config->GetInt(name_space_ + "/core_word_length", &core_word_length_);
190	    config->GetBool(name_space_ + "/always_show_comments",
191	                    &always_show_comments_);
192	    config->GetBool(name_space_ + "/enable_correction", &enable_correction_);
193	    if (!config->GetBool(name_space_ + "/enable_word_completion",
194	                         &enable_word_completion_)) {
195	      enable_word_completion_ = enable_completion_;
196	    }
197	    config->GetInt(name_space_ + "/max_homophones", &max_homophones_);
198	    poet_.reset(new Poet(language(), config));
199	  }
200	  if (enable_correction_) {
201	    if (auto* corrector = Corrector::Require("corrector")) {
202	      corrector_.reset(corrector->Create(ticket));
203	    }
204	  }
205	}
206	
207	an<Translation> ScriptTranslator::Query(const string& input,
208	                                        const Segment& segment) {
209	  if (!dict_ || !dict_->loaded())
210	    return nullptr;
211	  if (!segment.HasAnyTagIn(tags_))
212	    return nullptr;
213	  DLOG(INFO) << "input = '" << input << "', [" << segment.start << ", "
214	             << segment.end << ")";
215	
216	  FinishSession();
217	
218	  bool enable_user_dict =
219	      user_dict_ && user_dict_->loaded() && !IsUserDictDisabledFor(input);
220	
221	  size_t end_of_input = engine_->context()->input().length();
222	  // the translator should survive translations it creates
223	  auto result = New<ScriptTranslation>(
224	      this, corrector_.get(), poet_.get(), input, segment.start, end_of_input,
225	      max_sentences_, sentence_cutoff_threshold_);
226	  if (!result || !result->Evaluate(
227	                     dict_.get(), enable_user_dict ? user_dict_.get() : NULL)) {
228	    return nullptr;
229	  }
230	  auto deduped = New<DistinctTranslation>(result);
231	  if (contextual_suggestions_) {
232	    return poet_->ContextualWeighted(deduped, input, segment.start, this);
233	  }
234	  return deduped;
235	}
236	
237	int ScriptTranslator::core_word_length() const {
238	  if (max_word_length_ <= 0) {
239	    return core_word_length_;
240	  }
241	  return (std::min)(core_word_length_, max_word_length_);
242	}
243	
244	static bool exceed_upperlimit(int length, int upper_limit) {
245	  return upper_limit > 0 && length > upper_limit;
246	}
247	
248	bool ScriptTranslator::SaveCommitEntry(CommitEntry& commit_entry) {
249	  if (exceed_upperlimit(commit_entry.Length(), max_word_length())) {
250	    UpdateElements(commit_entry);
251	  } else {
252	    commit_entry.Save();
253	  }
254	  return true;
255	}
256	
257	bool ScriptTranslator::ConcatenatePhrases(CommitEntry& commit_entry,
258	                                          const vector<an<Phrase>>& phrases) {
259	  const int kCoreWordLength = core_word_length();
260	  const int n = phrases.size();
261	  for (int i = 0; i < n; ++i) {
262	    int cur_len = 0;
263	    int j = i;
264	    for (; j < n; ++j) {
265	      commit_entry.AppendPhrase(phrases.at(j));
266	      cur_len += phrases.at(j)->code().size();
267	      if (kCoreWordLength <= 0 || cur_len > kCoreWordLength) {
268	        break;
269	      }
270	      SaveCommitEntry(commit_entry);
271	    }
272	    if (kCoreWordLength > 0) {
273	      if (j == i) {
274	        SaveCommitEntry(commit_entry);
275	      }
276	      commit_entry.Clear();
277	    }
278	  }
279	  SaveCommitEntry(commit_entry);
280	  commit_entry.Clear();
281	
282	  return true;
283	}
284	
285	bool ScriptTranslator::ProcessSegmentOnCommit(CommitEntry& commit_entry,
286	                                              const Segment& seg) {
287	  auto phrase =
288	      As<Phrase>(Candidate::GetGenuineCandidate(seg.GetSelectedCandidate()));
289	  bool recognized = Language::intelligible(phrase, this);
290	  if (recognized) {
291	    queue_.push_back(phrase);
292	  }
293	
294	  if (!recognized || seg.status >= Segment::kConfirmed) {
295	    ConcatenatePhrases(commit_entry, queue_);
296	    queue_.clear();
297	  }
298	
299	  return true;
300	}
