302	string ScriptTranslator::FormatPreedit(const string& preedit) {
303	  string result = preedit;
304	  preedit_formatter_.Apply(&result);
305	  return result;
306	}
307	
308	string ScriptTranslator::Spell(const Code& code) {
309	  string result;
310	  vector<string> syllables;
311	  if (!dict_ || !dict_->Decode(code, &syllables) || syllables.empty())
312	    return result;
313	  result = boost::algorithm::join(syllables, string(1, delimiters_.at(0)));
314	  comment_formatter_.Apply(&result);
315	  return result;
316	}
317	
318	string ScriptTranslator::GetPrecedingText(size_t start) const {
319	  return !contextual_suggestions_ ? string()
320	         : start > 0 ? engine_->context()->composition().GetTextBefore(start)
321	                     : engine_->context()->commit_history().latest_text();
322	}
323	
324	bool ScriptTranslator::UpdateElements(const CommitEntry& commit_entry) {
325	  bool update_elements = false;
326	  // avoid updating single character entries within a phrase which is
327	  // composed with single characters only
328	  if (commit_entry.elements.size() > 1) {
329	    for (const DictEntry* e : commit_entry.elements) {
330	      if (e->code.size() > 1) {
331	        update_elements = true;
332	        break;
333	      }
334	    }
335	  }
336	  if (update_elements) {
337	    for (const DictEntry* e : commit_entry.elements) {
338	      user_dict_->UpdateEntry(*e, 0);
339	    }
340	  }
341	  return true;
342	}
343	
344	bool ScriptTranslator::Memorize(const CommitEntry& commit_entry) {
345	  UpdateElements(commit_entry);
346	  user_dict_->UpdateEntry(commit_entry, 1);
347	  return true;
348	}
349	
350	// ScriptSyllabifier implementation
351	
352	Spans ScriptSyllabifier::Syllabify(const Phrase* phrase) {
353	  Spans result;
354	  vector<size_t> vertices;
355	  vertices.push_back(start_);
356	  SyllabifyTask task{
357	      phrase->code(), syllable_graph_, phrase->end() - start_,
358	      [&](SyllabifyTask* task, size_t depth, size_t current_pos,
359	          size_t next_pos) { vertices.push_back(start_ + next_pos); },
360	      [&](SyllabifyTask* task, size_t depth) { vertices.pop_back(); }};
361	  if (syllabify_dfs(&task, 0, phrase->start() - start_)) {
362	    result.set_vertices(std::move(vertices));
363	  }
364	  return result;
365	}
366	
367	size_t ScriptSyllabifier::BuildSyllableGraph(Prism& prism) {
368	  return (size_t)syllabifier_.BuildSyllableGraph(input_, prism,
369	                                                 &syllable_graph_);
370	}
371	
372	bool ScriptSyllabifier::IsCorrection(const Code& code,
373	                                     size_t code_length) const {
374	  vector<bool> path_attributes;
375	  path_attributes.reserve(8);
376	
377	  SyllabifyTask task{
378	      code, syllable_graph_, code_length,
379	      // push
380	      [&](SyllabifyTask* task, size_t depth, size_t current_pos,
381	          size_t next_pos) {
382	        auto id = task->code[depth];
383	
384	        auto start_iter = syllable_graph_.edges.find(current_pos);
385	        if (start_iter != syllable_graph_.edges.end()) {
386	          auto end_iter = start_iter->second.find(next_pos);
387	          if (end_iter != start_iter->second.end()) {
388	            auto prop_iter = end_iter->second.find(id);
389	            if (prop_iter != end_iter->second.end()) {
390	              path_attributes.push_back(prop_iter->second.is_correction);
391	              return;
392	            }
393	          }
394	        }
395	        // edge not found
396	        path_attributes.push_back(false);
397	      },
398	      // pop
399	      [&](SyllabifyTask* task, size_t depth) { path_attributes.pop_back(); }};
400	
401	  if (syllabify_dfs(&task, 0, 0)) {
402	    for (bool is_correction : path_attributes) {
403	      if (is_correction)
404	        return true;
405	    }
406	  }
407	  return false;
408	}
409	
410	string ScriptSyllabifier::GetPreeditString(const Phrase& cand) const {
411	  const auto& delimiters = translator_->delimiters();
412	  std::stack<size_t> lengths;
413	  string output;
414	  SyllabifyTask task{cand.matching_code(), syllable_graph_, cand.end() - start_,
415	                     [&](SyllabifyTask* task, size_t depth, size_t current_pos,
416	                         size_t next_pos) {
417	                       size_t len = output.length();
418	                       if (depth > 0 && len > 0 &&
419	                           delimiters.find(output[len - 1]) == string::npos) {
420	                         output += delimiters.at(0);
421	                       }
422	                       output +=
423	                           input_.substr(current_pos, next_pos - current_pos);
424	                       lengths.push(len);
425	                     },
426	                     [&](SyllabifyTask* task, size_t depth) {
427	                       output.resize(lengths.top());
428	                       lengths.pop();
429	                     }};
430	  if (syllabify_dfs(&task, 0, cand.start() - start_)) {
431	    return translator_->FormatPreedit(output);
432	  } else {
433	    return string();
434	  }
435	}
436	
437	string ScriptSyllabifier::GetOriginalSpelling(const Phrase& cand) const {
438	  if (translator_ &&
439	      static_cast<int>(cand.code().size()) <= translator_->spelling_hints()) {
440	    return translator_->Spell(cand.code());
441	  }
442	  return string();
443	}
444	
445	template <class Ptr, class Iter>
446	static bool has_exact_match_phrase(Ptr ptr, Iter iter, size_t consumed) {
447	  return ptr && iter->first == consumed && !iter->second.exhausted() &&
448	         iter->second.Peek()->IsExactMatch();
449	}
450	
451	// ScriptTranslation implementation
452	
453	bool ScriptTranslation::Evaluate(Dictionary* dict, UserDictionary* user_dict) {
454	  size_t consumed = syllabifier_->BuildSyllableGraph(*dict->prism());
455	  const auto& syllable_graph = syllabifier_->syllable_graph();
456	  bool predict_word = translator_->enable_word_completion() &&
457	                      start_ + consumed == end_of_input_;
458	
459	  phrase_ =
460	      dict->Lookup(syllable_graph, 0, &translator_->blacklist(), predict_word);
461	  if (user_dict) {
462	    const size_t kUnlimitedDepth = 0;
463	    const size_t kNumSyllablesToPredictWord = 4;
464	    user_phrase_ =
465	        user_dict->Lookup(syllable_graph, 0, kUnlimitedDepth,
466	                          predict_word ? kNumSyllablesToPredictWord : 0);
467	  }
468	  if (!phrase_ && !user_phrase_)
469	    return false;
470	
471	  if (phrase_)
472	    phrase_iter_ = phrase_->rbegin();
473	  if (user_phrase_)
474	    user_phrase_iter_ = user_phrase_->rbegin();
475	
476	  auto is_correction_match = [&](auto& iter_pair, size_t len) {
477	    if (iter_pair.first != len || iter_pair.second.exhausted())
478	      return false;
479	    return syllabifier_->IsCorrection(iter_pair.second.Peek()->code, len);
480	  };
481	
482	  bool has_reliable_phrase =
483	      has_exact_match_phrase(phrase_, phrase_iter_, consumed) &&
484	      !is_correction_match(*phrase_iter_, consumed);
485	
486	  bool has_reliable_user_phrase =
487	      has_exact_match_phrase(user_phrase_, user_phrase_iter_, consumed) &&
488	      !is_correction_match(*user_phrase_iter_, consumed);
489	
490	  bool has_at_least_two_syllables = syllable_graph.edges.size() >= 2;
491	  DLOG(INFO) << "consumed: " << consumed
492	             << ", has_reliable_phrase: " << has_reliable_phrase
493	             << ", has_reliable_user_phrase: " << has_reliable_user_phrase
494	             << ", has_at_least_two_syllables: " << has_at_least_two_syllables;
495	  // make sentences when there is no exact-matching phrase candidate
496	  if (has_at_least_two_syllables && !has_reliable_phrase &&
497	      !has_reliable_user_phrase) {
498	    if (max_sentences_ > 1)
499	      sentences_ = MakeSentences(dict, user_dict);
500	    else if (max_sentences_) {
501	      auto sentence = MakeSentence(dict, user_dict);
502	      if (sentence)
503	        sentences_ = {sentence};
504	      else
505	        sentences_.clear();
506	    }
507	  }
508	
509	  return !CheckEmpty();
510	}
511	
512	bool ScriptTranslation::Next() {
513	  do {
514	    if (exhausted())
515	      return false;
516	    if (candidate_source_ == kUninitialized) {
517	      PrepareCandidate();  // to determine candidate_source_
518	    }
519	    switch (candidate_source_) {
520	      case kUninitialized:
521	        break;
522	      case kSentence:
523	        if (!sentences_.empty())
524	          sentences_.pop_front();
525	        break;
526	      case kUserPhrase: {
527	        UserDictEntryIterator& uter(user_phrase_iter_->second);
528	        if (!uter.Next()) {
529	          ++user_phrase_iter_;
530	        }
531	      } break;
532	      case kSysPhrase: {
533	        DictEntryIterator& iter(phrase_iter_->second);
534	        if (!iter.Next()) {
535	          ++phrase_iter_;
536	        }
537	      } break;
538	    }
539	    candidate_.reset();
540	    candidate_source_ = kUninitialized;
541	    if (enable_correction_) {
542	      // populate next candidate and skip it if it's a correction beyond max
543	      // numbers.
544	      if (!PrepareCandidate()) {
545	        break;
546	      }
547	    }
548	  } while (enable_correction_ &&
549	           syllabifier_->IsCorrection(candidate_->code(),
550	                                      candidate_->end() - start_) &&
551	           // limit the number of correction candidates
552	           ++correction_count_ > max_corrections_);
553	  if (!CheckEmpty()) {
554	    ++candidate_index_;
555	    return true;
556	  }
557	  return false;
558	}
559	
560	an<Candidate> ScriptTranslation::Peek() {
561	  if (candidate_source_ == kUninitialized && !PrepareCandidate()) {
562	    return nullptr;
563	  }
564	  if (candidate_->preedit().empty()) {
565	    candidate_->set_preedit(syllabifier_->GetPreeditString(*candidate_));
566	  }
567	  if (candidate_->comment().empty()) {
568	    auto spelling = syllabifier_->GetOriginalSpelling(*candidate_);
569	    if (!spelling.empty() && (translator_->always_show_comments() ||
570	                              spelling != candidate_->preedit())) {
571	      candidate_->set_comment(/*quote_left + */ spelling /* + quote_right*/);
572	    }
573	  }
574	  candidate_->set_syllabifier(syllabifier_);
575	  return candidate_;
576	}
577	
578	static bool always_true() {
579	  return true;
580	}
581	
582	template <typename T>
583	inline static bool prefer_user_phrase(
584	    T user_phrase_weight,
585	    T sys_phrase_weight,
586	    function<bool()> compare_on_tie = always_true) {
587	  return user_phrase_weight > sys_phrase_weight ||
588	         (user_phrase_weight == sys_phrase_weight && compare_on_tie());
589	}
590	
591	bool ScriptTranslation::PrepareCandidate() {
592	iter_incremented:
593	  if (exhausted()) {
594	    candidate_source_ = kUninitialized;
595	    candidate_ = nullptr;
596	    return false;
597	  }
598	  if (!sentences_.empty()) {
599	    candidate_source_ = kSentence;
600	    candidate_ = sentences_[0];
601	    return true;
602	  }
603	  const size_t full_code_length = end_of_input_ - start_;
604	  size_t user_phrase_code_length = 0;
605	  if (user_phrase_ && user_phrase_iter_ != user_phrase_->rend()) {
606	    user_phrase_code_length = user_phrase_iter_->first;
607	  }
608	  size_t phrase_code_length = 0;
609	  if (phrase_ && phrase_iter_ != phrase_->rend()) {
610	    phrase_code_length = phrase_iter_->first;
611	  }
612	  if (user_phrase_code_length > 0 &&
613	      prefer_user_phrase(
614	          user_phrase_code_length, phrase_code_length,
615	          // 編碼長度相同時, 用戶詞優先
616	          [this, full_code_length, phrase_code_length]() {
617	            UserDictEntryIterator& uter = user_phrase_iter_->second;
618	            DictEntryIterator& iter = phrase_iter_->second;
619	            // 但若用戶詞爲糾錯結果, 則免去優先權, 回歸權重比較
620	            bool user_is_correction = syllabifier_->IsCorrection(
621	                uter.Peek()->code, phrase_code_length);
622	            if (user_is_correction) {
623	              // 因對糾錯候選施加了較大懲罰, 通常結果爲 系統原文 > 用戶糾錯
624	              // 兩者皆糾錯時, 用戶詞的動態權重有助達成 用戶糾錯 > 系統糾錯
625	              return uter.Peek()->weight >= iter.Peek()->weight;
626	            }
627	            // 長詞聯想之前須至少出一個嚴格匹配的候選
628	            // 故確定首選之際, 系統嚴格匹配 > 用戶長詞聯想
629	            const int kNumExactMatchOnTop = 1;
630	            return candidate_index_ >= kNumExactMatchOnTop ||
631	                   prefer_user_phrase(
632	                       has_exact_match_phrase(user_phrase_, user_phrase_iter_,
633	                                              full_code_length),
634	                       has_exact_match_phrase(phrase_, phrase_iter_,
635	                                              full_code_length));
636	          })) {
637	    UserDictEntryIterator& uter = user_phrase_iter_->second;
638	    const auto& entry = uter.Peek();
639	    DLOG(INFO) << "user phrase '" << entry->text
640	               << "', code length: " << user_phrase_code_length;
641	    candidate_source_ = kUserPhrase;
642	    candidate_ =
643	        New<Phrase>(translator_->language(),
644	                    entry->IsPredictiveMatch() ? "completion" : "user_phrase",
645	                    start_, start_ + user_phrase_code_length, entry);
646	    candidate_->set_quality(std::exp(entry->weight) +
647	                            translator_->initial_quality() +
648	                            (entry->quality_len / full_code_length));
649	    return true;
650	  } else if (phrase_code_length > 0) {
651	    DictEntryIterator& iter = phrase_iter_->second;
652	    if (iter.exhausted()) {
653	      ++phrase_iter_;
654	      goto iter_incremented;
655	    }
656	    const auto& entry = iter.Peek();
657	    DLOG(INFO) << "phrase '" << entry->text
658	               << "', code length: " << phrase_code_length;
659	    candidate_source_ = kSysPhrase;
660	    candidate_ =
661	        New<Phrase>(translator_->language(),
662	                    entry->IsPredictiveMatch() ? "completion" : "phrase",
663	                    start_, start_ + phrase_code_length, entry);
664	    candidate_->set_quality(std::exp(entry->weight) +
665	                            translator_->initial_quality() +
666	                            (entry->quality_len / full_code_length));
667	    return true;
668	  } else {
669	    candidate_source_ = kUninitialized;
670	    candidate_ = nullptr;
671	    return false;
672	  }
673	}
674	
675	bool ScriptTranslation::CheckEmpty() {
676	  set_exhausted((!phrase_ || phrase_iter_ == phrase_->rend()) &&
677	                (!user_phrase_ || user_phrase_iter_ == user_phrase_->rend()));
678	  return exhausted();
679	}
680	
681	template <class QueryResult>
682	void ScriptTranslation::EnrollEntries(
683	    map<int, DictEntryList>& entries_by_end_pos,
684	    const an<QueryResult>& query_result) {
685	  if (query_result) {
686	    for (auto& y : *query_result) {
687	      DictEntryList& homophones = entries_by_end_pos[y.first];
688	      while (homophones.size() < translator_->max_homophones() &&
689	             !y.second.exhausted()) {
690	        homophones.push_back(y.second.Peek());
691	        if (!y.second.Next())
692	          break;
693	      }
694	    }
695	  }
696	}
697	
698	WordGraph ScriptTranslation::PrepareForMakingSentence(
699	    Dictionary* dict,
700	    UserDictionary* user_dict) {
701	  const int kMaxSyllablesForUserPhraseQuery = 5;
702	  const auto& syllable_graph = syllabifier_->syllable_graph();
703	  WordGraph graph;
704	  for (const auto& x : syllable_graph.edges) {
705	    auto& same_start_pos = graph[x.first];
706	    if (user_dict) {
707	      EnrollEntries(same_start_pos,
708	                    user_dict->Lookup(syllable_graph, x.first,
709	                                      kMaxSyllablesForUserPhraseQuery));
710	    }
711	    // merge lookup results
712	    EnrollEntries(same_start_pos, dict->Lookup(syllable_graph, x.first,
713	                                               &translator_->blacklist()));
714	  }
715	  return graph;
716	}
717	
718	deque<an<Sentence>> ScriptTranslation::MakeSentences(
719	    Dictionary* dict,
720	    UserDictionary* user_dict) {
721	  const auto& syllable_graph = syllabifier_->syllable_graph();
722	  WordGraph graph = PrepareForMakingSentence(dict, user_dict);
723	  auto sentences =
724	      poet_->MakeSentences(graph, syllable_graph.interpreted_length,
725	                           translator_->GetPrecedingText(start_),
726	                           max_sentences_, sentence_cutoff_threshold_);
727	  for (auto& sentence : sentences) {
728	    sentence->Offset(start_);
729	    sentence->set_syllabifier(syllabifier_);
730	  }
731	  return sentences;
732	}
733	
734	an<Sentence> ScriptTranslation::MakeSentence(Dictionary* dict,
735	                                             UserDictionary* user_dict) {
736	  const auto& syllable_graph = syllabifier_->syllable_graph();
737	  WordGraph graph = PrepareForMakingSentence(dict, user_dict);
738	  if (auto sentence =
739	          poet_->MakeSentence(graph, syllable_graph.interpreted_length,
740	                              translator_->GetPrecedingText(start_))) {
741	    sentence->Offset(start_);
742	    sentence->set_syllabifier(syllabifier_);
743	    return sentence;
744	  }
745	  return nullptr;
746	}
747	
748	}  // namespace rime
