28	
29	static const char* kUnitySymbol = " \xe2\x98\xaf ";
30	
31	// TableTranslation
32	
33	TableTranslation::TableTranslation(TranslatorOptions* options,
34	                                   const Language* language,
35	                                   const string& input,
36	                                   size_t start,
37	                                   size_t end,
38	                                   const string& preedit,
39	                                   DictEntryIterator&& iter,
40	                                   UserDictEntryIterator&& uter)
41	    : options_(options),
42	      language_(language),
43	      input_(input),
44	      start_(start),
45	      end_(end),
46	      preedit_(preedit),
47	      iter_(std::move(iter)),
48	      uter_(std::move(uter)) {
49	  if (options_)
50	    options_->preedit_formatter().Apply(&preedit_);
51	  CheckEmpty();
52	}
53	
54	bool TableTranslation::Next() {
55	  if (exhausted())
56	    return false;
57	  if (PreferUserPhrase()) {
58	    uter_.Next();
59	    if (uter_.exhausted())
60	      FetchMoreUserPhrases();
61	  } else {
62	    iter_.Next();
63	    if (iter_.exhausted())
64	      FetchMoreTableEntries();
65	  }
66	  return !CheckEmpty();
67	}
68	
69	static bool is_constructed(const DictEntry* e) {
70	  return UnityTableEncoder::HasPrefix(e->custom_code);
71	}
72	
73	an<Candidate> TableTranslation::Peek() {
74	  if (exhausted())
75	    return nullptr;
76	  bool is_user_phrase = PreferUserPhrase();
77	  auto e = PreferredEntry(is_user_phrase);
78	  string comment(is_constructed(e.get()) ? kUnitySymbol : e->comment);
79	  if (options_) {
80	    options_->comment_formatter().Apply(&comment);
81	  }
82	  bool incomplete = e->remaining_code_length != 0;
83	  auto type = incomplete       ? "completion"
84	              : is_user_phrase ? "user_table"
85	                               : "table";
86	  auto phrase = New<Phrase>(language_, type, start_, end_, e);
87	  if (phrase) {
88	    phrase->set_comment(comment);
89	    phrase->set_preedit(preedit_);
90	    phrase->set_quality(std::exp(e->weight) + options_->initial_quality() +
91	                        (incomplete ? -1 : 0) + (is_user_phrase ? 0.5 : 0));
92	  }
93	  return phrase;
94	}
95	
96	bool TableTranslation::CheckEmpty() {
97	  bool is_empty = iter_.exhausted() && uter_.exhausted();
98	  set_exhausted(is_empty);
99	  return is_empty;
100	}
101	
102	bool TableTranslation::PreferUserPhrase() {
103	  if (uter_.exhausted())
104	    return false;
105	  if (iter_.exhausted())
106	    return true;
107	  if (iter_.Peek()->remaining_code_length == 0 &&
108	      (uter_.Peek()->remaining_code_length != 0 ||
109	       is_constructed(uter_.Peek().get())))
110	    return false;
111	  else
112	    return true;
113	}
114	
115	// LazyTableTranslation
116	
117	class LazyTableTranslation : public TableTranslation {
118	 public:
119	  static const size_t kInitialSearchLimit = 10;
120	  static const size_t kExpandingFactor = 10;
121	
122	  LazyTableTranslation(TableTranslator* translator,
123	                       const string& input,
124	                       size_t start,
125	                       size_t end,
126	                       const string& preedit,
127	                       bool enable_user_dict);
128	  bool FetchUserPhrases(TableTranslator* translator);
129	  virtual bool FetchMoreUserPhrases();
130	  virtual bool FetchMoreTableEntries();
131	
132	 private:
133	  Dictionary* dict_;
134	  const hash_set<string>* blacklist_;
135	  UserDictionary* user_dict_;
136	  size_t limit_;
137	  size_t user_dict_limit_;
138	  string user_dict_key_;
139	};
140	
141	LazyTableTranslation::LazyTableTranslation(TableTranslator* translator,
142	                                           const string& input,
143	                                           size_t start,
144	                                           size_t end,
145	                                           const string& preedit,
146	                                           bool enable_user_dict)
147	    : TableTranslation(translator,
148	                       translator->language(),
149	                       input,
150	                       start,
151	                       end,
152	                       preedit),
153	      dict_(translator->dict()),
154	      blacklist_(&translator->blacklist()),
155	      user_dict_(enable_user_dict ? translator->user_dict() : NULL),
156	      limit_(kInitialSearchLimit),
157	      user_dict_limit_(kInitialSearchLimit) {
158	  FetchUserPhrases(translator) || FetchMoreUserPhrases();
159	  FetchMoreTableEntries();
160	  CheckEmpty();
161	}
162	
163	bool LazyTableTranslation::FetchUserPhrases(TableTranslator* translator) {
164	  if (!user_dict_)
165	    return false;
166	  // fetch all exact match entries
167	  user_dict_->LookupWords(&uter_, input_, false, 0, &user_dict_key_);
168	  auto encoder = translator->encoder();
169	  if (encoder && encoder->loaded()) {
170	    encoder->LookupPhrases(&uter_, input_, false);
171	  }
172	  return !uter_.exhausted();
173	}
174	
175	bool LazyTableTranslation::FetchMoreUserPhrases() {
176	  if (!user_dict_ || user_dict_limit_ == 0)
177	    return false;
178	  size_t count = user_dict_->LookupWords(&uter_, input_, true, user_dict_limit_,
179	                                         &user_dict_key_);
180	  if (count < user_dict_limit_) {
181	    DLOG(INFO) << "all user dict entries obtained.";
182	    user_dict_limit_ = 0;  // no more try
183	  } else {
184	    user_dict_limit_ *= kExpandingFactor;
185	  }
186	  return !uter_.exhausted();
187	}
188	
189	bool LazyTableTranslation::FetchMoreTableEntries() {
190	  if (!dict_ || limit_ == 0)
191	    return false;
192	  size_t previous_entry_count = iter_.entry_count();
193	  DLOG(INFO) << "fetching more table entries: limit = " << limit_
194	             << ", count = " << previous_entry_count;
195	  DictEntryIterator more;
196	  if (dict_->LookupWords(&more, input_, true, limit_, blacklist_) < limit_) {
197	    DLOG(INFO) << "all table entries obtained.";
198	    limit_ = 0;  // no more try
199	  } else {
200	    limit_ *= kExpandingFactor;
201	  }
202	  if (more.entry_count() > previous_entry_count) {
203	    more.Skip(previous_entry_count);
204	    iter_ = std::move(more);
205	  }
206	  return true;
207	}
208	
209	// TableTranslator
210	
211	TableTranslator::TableTranslator(const Ticket& ticket)
212	    : Translator(ticket), Memory(ticket), TranslatorOptions(ticket) {
213	  if (!engine_)
214	    return;
215	  if (Config* config = engine_->schema()->config()) {
216	    config->GetBool(name_space_ + "/enable_charset_filter",
217	                    &enable_charset_filter_);
218	    config->GetBool(name_space_ + "/enable_sentence", &enable_sentence_);
219	    config->GetBool(name_space_ + "/sentence_over_completion",
220	                    &sentence_over_completion_);
221	    config->GetBool(name_space_ + "/enable_encoder", &enable_encoder_);
222	    config->GetBool(name_space_ + "/encode_commit_history",
223	                    &encode_commit_history_);
224	    config->GetInt(name_space_ + "/max_phrase_length", &max_phrase_length_);
225	    config->GetInt(name_space_ + "/max_homographs", &max_homographs_);
226	    if (enable_sentence_ || sentence_over_completion_ ||
227	        contextual_suggestions_) {
228	      poet_.reset(new Poet(language(), config, Poet::LeftAssociateCompare));
229	    }
230	  }
231	  if (enable_encoder_ && user_dict_) {
232	    encoder_.reset(new UnityTableEncoder(user_dict_.get()));
233	    encoder_->Load(ticket);
234	  }
235	}
236	
237	static bool starts_with_completion(an<Translation> translation) {
238	  if (!translation)
239	    return false;
240	  auto cand = translation->Peek();
241	  return cand && cand->type() == "completion";
242	}
243	
244	an<Translation> TableTranslator::Query(const string& input,
245	                                       const Segment& segment) {
246	  if (!segment.HasAnyTagIn(tags_))
247	    return nullptr;
248	  DLOG(INFO) << "input = '" << input << "', [" << segment.start << ", "
249	             << segment.end << ")";
250	
251	  FinishSession();
252	
253	  bool enable_user_dict =
254	      user_dict_ && user_dict_->loaded() && !IsUserDictDisabledFor(input);
255	
256	  const string& preedit(input);
257	  string code = input;
258	  boost::trim_right_if(code, boost::is_any_of(delimiters_));
259	
260	  an<Translation> translation;
261	  if (enable_completion_) {
262	    translation = Cached<LazyTableTranslation>(this, code, segment.start,
263	                                               segment.start + input.length(),
264	                                               preedit, enable_user_dict);
265	  } else {
266	    DictEntryIterator iter;
267	    if (dict_ && dict_->loaded()) {
268	      dict_->LookupWords(&iter, code, false, 0, &blacklist());
269	    }
270	    UserDictEntryIterator uter;
271	    if (enable_user_dict) {
272	      user_dict_->LookupWords(&uter, code, false);
273	      if (encoder_ && encoder_->loaded()) {
274	        encoder_->LookupPhrases(&uter, code, false);
275	      }
276	    }
277	    if (!iter.exhausted() || !uter.exhausted())
278	      translation = Cached<TableTranslation>(
279	          this, language(), code, segment.start, segment.start + input.length(),
280	          preedit, std::move(iter), std::move(uter));
281	  }
282	  if (translation) {
283	    bool filter_by_charset =
284	        enable_charset_filter_ &&
285	        !engine_->context()->get_option("extended_charset");
286	    if (filter_by_charset) {
287	      translation = New<CharsetFilterTranslation>(translation);
288	    }
289	  }
290	  if (translation && translation->exhausted()) {
291	    translation.reset();  // discard futile translation
292	  }
293	  if (enable_sentence_ && !translation) {
294	    translation = MakeSentence(input, segment.start,
295	                               /* include_prefix_phrases = */ true);
296	  } else if (sentence_over_completion_ && starts_with_completion(translation)) {
297	    if (auto sentence = MakeSentence(input, segment.start)) {
298	      translation = sentence + translation;
299	    }
300	  }
301	  if (translation && translation->exhausted()) {
302	    return nullptr;
303	  }
304	  translation = New<DistinctTranslation>(translation);
305	  if (contextual_suggestions_) {
306	    return poet_->ContextualWeighted(translation, input, segment.start, this);
307	  }
308	  return translation;
309	}
310	
311	bool TableTranslator::Memorize(const CommitEntry& commit_entry) {
312	  if (!user_dict_)
313	    return false;
314	  for (const DictEntry* e : commit_entry.elements) {
315	    if (is_constructed(e)) {
316	      DictEntry blessed(*e);
317	      UnityTableEncoder::RemovePrefix(&blessed.custom_code);
318	      user_dict_->UpdateEntry(blessed, 1);
319	    } else {
320	      user_dict_->UpdateEntry(*e, 1);
321	    }
322	  }
323	  if (encoder_ && encoder_->loaded()) {
324	    if (commit_entry.elements.size() > 1) {
325	      encoder_->EncodePhrase(commit_entry.text, "1");
326	    }
327	    if (encode_commit_history_) {
328	      const auto& history(engine_->context()->commit_history());
329	      if (!history.empty()) {
330	        DLOG(INFO) << "history: " << history.repr();
331	        auto it = history.rbegin();
332	        if (it->type == "punct") {  // ending with punctuation
333	          ++it;
334	        }
335	        string phrase;
336	        for (; it != history.rend(); ++it) {
337	          if (it->type != "table" && it->type != "user_table" &&
338	              it->type != "sentence" && it->type != "uniquified")
339	            break;
340	          if (phrase.empty()) {
341	            phrase = it->text;  // last word
342	            continue;
343	          }
344	          phrase = it->text + phrase;  // prepend another word
345	          size_t phrase_length = utf8::unchecked::distance(
346	              phrase.c_str(), phrase.c_str() + phrase.length());
347	          if (static_cast<int>(phrase_length) > max_phrase_length_)
348	            break;
349	          DLOG(INFO) << "phrase: " << phrase;
350	          encoder_->EncodePhrase(phrase, "0");
351	        }
352	      }
353	    }
354	  }
355	  return true;
356	}
357	
358	string TableTranslator::GetPrecedingText(size_t start) const {
359	  return !contextual_suggestions_ ? string()
360	         : start > 0 ? engine_->context()->composition().GetTextBefore(start)
361	                     : engine_->context()->commit_history().latest_text();
362	}
363	
364	// SentenceSyllabifier
365	
366	class SentenceSyllabifier : public PhraseSyllabifier {
367	 public:
368	  virtual Spans Syllabify(const Phrase* phrase);
369	};
370	
371	Spans SentenceSyllabifier::Syllabify(const Phrase* phrase) {
372	  Spans result;
373	  if (auto sentence = dynamic_cast<const Sentence*>(phrase)) {
374	    size_t stop = sentence->start();
375	    result.AddVertex(stop);
376	    for (size_t len : sentence->word_lengths()) {
377	      stop += len;
378	      result.AddVertex(stop);
379	    }
380	  }
381	  return result;
382	}
383	
384	// SentenceTranslation
385	
386	class SentenceTranslation : public Translation {
387	 public:
388	  SentenceTranslation(TableTranslator* translator,
389	                      an<Sentence>&& sentence,
390	                      DictEntryCollector&& collector,
391	                      UserDictEntryCollector&& ucollector,
392	                      const string& input,
393	                      size_t start);
394	  virtual bool Next();
395	  virtual an<Candidate> Peek();
396	
397	 protected:
398	  void PrepareSentence();
399	  bool CheckEmpty();
400	  bool PreferUserPhrase() const;
401	
402	  TableTranslator* translator_;
403	  an<Sentence> sentence_;
404	  DictEntryCollector collector_;
405	  UserDictEntryCollector user_phrase_collector_;
406	  string input_;
407	  size_t start_;
408	};
409	
410	SentenceTranslation::SentenceTranslation(TableTranslator* translator,
411	                                         an<Sentence>&& sentence,
412	                                         DictEntryCollector&& collector,
413	                                         UserDictEntryCollector&& ucollector,
414	                                         const string& input,
415	                                         size_t start)
416	    : translator_(translator),
417	      sentence_(std::move(sentence)),
418	      collector_(std::move(collector)),
419	      user_phrase_collector_(std::move(ucollector)),
420	      input_(input),
421	      start_(start) {
422	  PrepareSentence();
423	  CheckEmpty();
424	}
425	
426	bool SentenceTranslation::Next() {
427	  if (sentence_) {
428	    sentence_.reset();
429	    return !CheckEmpty();
430	  }
431	  if (PreferUserPhrase()) {
432	    auto r = user_phrase_collector_.rbegin();
433	    if (!r->second.Next()) {
434	      user_phrase_collector_.erase(r->first);
435	    }
436	  } else {
437	    auto r = collector_.rbegin();
438	    if (!r->second.Next()) {
439	      collector_.erase(r->first);
440	    }
441	  }
442	  return !CheckEmpty();
443	}
444	
445	an<Candidate> SentenceTranslation::Peek() {
446	  if (exhausted())
447	    return nullptr;
448	  if (sentence_) {
449	    return sentence_;
450	  }
451	  size_t code_length = 0;
452	  an<DictEntry> entry;
453	  bool is_user_phrase = PreferUserPhrase();
454	  if (is_user_phrase) {
455	    auto r = user_phrase_collector_.rbegin();
456	    code_length = r->first;
457	    entry = r->second.Peek();
458	  } else {
459	    auto r = collector_.rbegin();
460	    code_length = r->first;
461	    entry = r->second.Peek();
462	  }
463	  auto result = New<Phrase>(translator_ ? translator_->language() : NULL,
464	                            is_user_phrase ? "user_table" : "table", start_,
465	                            start_ + code_length, entry);
466	  if (translator_) {
467	    string preedit = input_.substr(0, code_length);
468	    translator_->preedit_formatter().Apply(&preedit);
469	    result->set_preedit(preedit);
470	  }
471	  return result;
472	}
473	
474	void SentenceTranslation::PrepareSentence() {
475	  if (!sentence_)
476	    return;
477	  sentence_->Offset(start_);
478	  sentence_->set_comment(kUnitySymbol);
479	  sentence_->set_syllabifier(New<SentenceSyllabifier>());
480	
481	  if (!translator_)
482	    return;
483	  string preedit = input_;
484	  const string& delimiters(translator_->delimiters());
485	  // split syllables
486	  size_t pos = 0;
487	  for (int len : sentence_->word_lengths()) {
488	    if (pos > 0 && delimiters.find(preedit[pos - 1]) == string::npos) {
489	      preedit.insert(pos, 1, ' ');
490	      ++pos;
491	    }
492	    pos += len;
493	  }
494	  translator_->preedit_formatter().Apply(&preedit);
495	  sentence_->set_preedit(preedit);
496	}
497	
498	bool SentenceTranslation::CheckEmpty() {
499	  set_exhausted(!sentence_ && collector_.empty() &&
500	                user_phrase_collector_.empty());
501	  return exhausted();
502	}
503	
504	bool SentenceTranslation::PreferUserPhrase() const {
505	  // compare code length
506	  int user_phrase_code_length = 0;
507	  int table_code_length = 0;
508	  if (!user_phrase_collector_.empty()) {
509	    user_phrase_code_length = user_phrase_collector_.rbegin()->first;
510	  }
511	  if (!collector_.empty()) {
512	    table_code_length = collector_.rbegin()->first;
513	  }
514	  if (user_phrase_code_length > 0 &&
515	      user_phrase_code_length >= table_code_length) {
516	    return true;
517	  }
518	  return false;
519	}
520	
521	inline static size_t consume_trailing_delimiters(size_t pos,
522	                                                 const string& input,
523	                                                 const string& delimiters) {
524	  while (pos < input.length() && delimiters.find(input[pos]) != string::npos) {
525	    ++pos;
526	  }
527	  return pos;
528	}
529	
530	template <class Iter>
531	inline static void collect_entries(DictEntryList& entries,
532	                                   Iter& iter,
533	                                   int max_entries) {
534	  if (entries.size() < max_entries && !iter.exhausted()) {
535	    entries.push_back(iter.Peek());
536	    // alters iter if collecting more than 1 entries
537	    while (entries.size() < max_entries && iter.Next()) {
538	      entries.push_back(iter.Peek());
539	    }
540	  }
541	}
542	
543	an<Translation> TableTranslator::MakeSentence(const string& input,
544	                                              size_t start,
545	                                              bool include_prefix_phrases) {
546	  bool filter_by_charset = enable_charset_filter_ &&
547	                           !engine_->context()->get_option("extended_charset");
548	  DictEntryCollector collector;
549	  UserDictEntryCollector user_phrase_collector;
550	  WordGraph graph;
551	  hash_set<int> vertices = {0};
552	  for (size_t start_pos = 0; start_pos < input.length(); ++start_pos) {
553	    // find next reachable vertex in word graph
554	    if (vertices.find(start_pos) == vertices.end())
555	      continue;
556	    string active_input = input.substr(start_pos);
557	    string active_key = active_input + ' ';
558	    auto& same_start_pos = graph[start_pos];
559	    // lookup dictionaries
560	    if (user_dict_ && user_dict_->loaded()) {
561	      for (size_t len = 1; len <= active_input.length(); ++len) {
562	        size_t consumed_length =
563	            consume_trailing_delimiters(len, active_input, delimiters_);
564	        size_t end_pos = start_pos + consumed_length;
565	        auto& homographs = same_start_pos[end_pos];
566	        if (homographs.size() >= max_homographs_)
567	          continue;
568	        DLOG(INFO) << "active input: " << active_input << "[0, " << len << ")";
569	        UserDictEntryIterator uter;
570	        string resume_key;
571	        string key = active_input.substr(0, len);
572	        user_dict_->LookupWords(&uter, key, false, 0, &resume_key);
573	        if (filter_by_charset) {
574	          uter.AddFilter(CharsetFilter::FilterDictEntry);
575	        }
576	        if (!uter.exhausted()) {
577	          vertices.insert(end_pos);
578	          if (start_pos == 0 && max_homographs_ > 1) {
579	            UserDictEntryIterator uter_copy(uter);
580	            collect_entries(homographs, uter_copy, max_homographs_);
581	          } else {
582	            collect_entries(homographs, uter, max_homographs_);
583	          }
584	          if (include_prefix_phrases && start_pos == 0) {
585	            // also provide words for manual composition
586	            // uter must not be consumed
587	            user_phrase_collector[consumed_length] = std::move(uter);
588	            DLOG(INFO) << "user phrase[" << consumed_length << "] cached: "
589	                       << user_phrase_collector[consumed_length].cache_size();
590	          }
591	        }
592	        if (resume_key > active_key &&
593	            !boost::starts_with(resume_key, active_key))
594	          break;
595	      }
596	    }
597	    if (encoder_ && encoder_->loaded()) {
598	      UnityTableEncoder::AddPrefix(&active_key);
599	      for (size_t len = 1; len <= active_input.length(); ++len) {
600	        size_t consumed_length =
601	            consume_trailing_delimiters(len, active_input, delimiters_);
602	        size_t end_pos = start_pos + consumed_length;
603	        auto& homographs = same_start_pos[end_pos];
604	        if (!homographs.empty())
605	          continue;
606	        DLOG(INFO) << "active input: " << active_input << "[0, " << len << ")";
607	        UserDictEntryIterator uter;
608	        string resume_key;
609	        string key = active_input.substr(0, len);
610	        encoder_->LookupPhrases(&uter, key, false, 0, &resume_key);
611	        if (filter_by_charset) {
612	          uter.AddFilter(CharsetFilter::FilterDictEntry);
613	        }
614	        if (!uter.exhausted()) {
615	          vertices.insert(end_pos);
616	          if (start_pos == 0 && max_homographs_ > 1) {
617	            UserDictEntryIterator uter_copy(uter);
618	            collect_entries(homographs, uter_copy, max_homographs_);
619	          } else {
620	            collect_entries(homographs, uter, max_homographs_);
621	          }
622	          if (include_prefix_phrases && start_pos == 0) {
623	            // also provide words for manual composition
624	            // uter must not be consumed
625	            user_phrase_collector[consumed_length] = std::move(uter);
626	            DLOG(INFO) << "unity phrase[" << consumed_length << "] cached: "
627	                       << user_phrase_collector[consumed_length].cache_size();
628	          }
629	        }
630	        if (resume_key > active_key &&
631	            !boost::starts_with(resume_key, active_key))
632	          break;
633	      }
634	    }
635	    if (dict_ && dict_->loaded()) {
636	      vector<Prism::Match> matches;
637	      dict_->prism()->CommonPrefixSearch(input.substr(start_pos), &matches);
638	      if (matches.empty())
639	        continue;
640	      for (const auto& m : boost::adaptors::reverse(matches)) {
641	        if (m.length == 0)
642	          continue;
643	        size_t consumed_length =
644	            consume_trailing_delimiters(m.length, active_input, delimiters_);
645	        size_t end_pos = start_pos + consumed_length;
646	        auto& homographs = same_start_pos[end_pos];
647	        if (homographs.size() >= max_homographs_)
648	          continue;
649	        DictEntryIterator iter;
650	        dict_->LookupWords(&iter, active_input.substr(0, m.length), false, 0,
651	                           &blacklist());
652	        if (filter_by_charset) {
653	          iter.AddFilter(CharsetFilter::FilterDictEntry);
654	        }
655	        if (!iter.exhausted()) {
656	          vertices.insert(end_pos);
657	          if (start_pos == 0 && max_homographs_ - homographs.size() > 1) {
658	            DictEntryIterator iter_copy = iter;
659	            collect_entries(homographs, iter_copy, max_homographs_);
660	          } else {
661	            collect_entries(homographs, iter, max_homographs_);
662	          }
663	          if (include_prefix_phrases && start_pos == 0) {
664	            // also provide words for manual composition
665	            // iter must not be consumed
666	            collector[consumed_length] = std::move(iter);
667	            DLOG(INFO) << "table[" << consumed_length
668	                       << "]: " << collector[consumed_length].entry_count();
669	          }
670	        }
671	      }
672	    }
673	  }
674	  if (auto sentence =
675	          poet_->MakeSentence(graph, input.length(), GetPrecedingText(start))) {
676	    auto result = Cached<SentenceTranslation>(
677	        this, std::move(sentence), std::move(collector),
678	        std::move(user_phrase_collector), input, start);
679	    if (result && filter_by_charset) {
680	      return New<CharsetFilterTranslation>(result);
681	    }
682	    return result;
683	  }
684	  return nullptr;
685	}
686	
687	}  // namespace rime
