55	class SchemaListTranslation : public FifoTranslation {
56	 public:
57	  SchemaListTranslation(Switcher* switcher) { LoadSchemaList(switcher); }
58	  virtual int Compare(an<Translation> other, const CandidateList& candidates);
59	
60	 protected:
61	  void LoadSchemaList(Switcher* switcher);
62	};
63	
64	int SchemaListTranslation::Compare(an<Translation> other,
65	                                   const CandidateList& candidates) {
66	  if (!other || other->exhausted())
67	    return -1;
68	  if (exhausted())
69	    return 1;
70	  // switches should immediately follow current schema (#0)
71	  auto theirs = other->Peek();
72	  if (theirs && theirs->type() == "unfold") {
73	    if (cursor_ == 0) {
74	      // unfold its options when the current schema is selected
75	      candies_[0] = New<SchemaAction>(candies_[0], theirs);
76	    }
77	    return cursor_ == 0 ? -1 : 1;
78	  }
79	  if (theirs && theirs->type() == "switch") {
80	    return cursor_ == 0 ? -1 : 1;
81	  }
82	  return Translation::Compare(other, candidates);
83	}
84	
85	void SchemaListTranslation::LoadSchemaList(Switcher* switcher) {
86	  Engine* engine = switcher->attached_engine();
87	  if (!engine)
88	    return;
89	  Config* config = switcher->schema()->config();
90	  if (!config)
91	    return;
92	  // current schema comes first
93	  Schema* current_schema = engine->schema();
94	  if (current_schema) {
95	    Append(New<SchemaSelection>(current_schema));
96	  }
97	  Config* user_config = switcher->user_config();
98	  size_t fixed = candies_.size();
99	  time_t now = time(NULL);
100	  // load the rest schema list
101	  Switcher::ForEachSchemaListEntry(config, [this, current_schema, user_config,
102	                                            now](const string& schema_id) {
103	    if (current_schema && schema_id == current_schema->schema_id())
104	      return /* continue = */ true;
105	    Schema schema(schema_id);
106	    auto cand = New<SchemaSelection>(&schema);
107	    int timestamp = 0;
108	    if (user_config && user_config->GetInt(
109	                           "var/schema_access_time/" + schema_id, &timestamp)) {
110	      if (timestamp <= now)
111	        cand->set_quality(timestamp);
112	    }
113	    Append(cand);
114	    return /* continue = */ true;
115	  });
116	  DLOG(INFO) << "num schemata: " << candies_.size();
117	  bool fix_order = false;
118	  config->GetBool("switcher/fix_schema_list_order", &fix_order);
119	  if (fix_order)
120	    return;
121	  // reorder schema list by recency
122	  std::stable_sort(candies_.begin() + fixed, candies_.end(),
123	                   [](const an<Candidate>& x, const an<Candidate>& y) {
124	                     return x->quality() > y->quality();
125	                   });
126	}
