203	void SwitchTranslation::LoadSwitches(Switcher* switcher) {
204	  Engine* engine = switcher->attached_engine();
205	  if (!engine)
206	    return;
207	  Config* config = engine->schema()->config();
208	  if (!config)
209	    return;
210	  Context* context = engine->context();
211	  vector<an<RadioGroup>> groups;
212	  Switches switches(config);
213	  switches.FindOption(
214	      [this, switcher, context,
215	       &groups](Switches::SwitchOption option) -> Switches::FindResult {
216	        if (!has_state_label(option, 0)) {
217	          return Switches::kContinue;
218	        }
219	        if (option.type == Switches::kToggleOption) {
220	          bool current_state = context->get_option(option.option_name);
221	          Append(New<Switch>(option, current_state,
222	                             switcher->IsAutoSave(option.option_name)));
223	        } else if (option.type == Switches::kRadioGroup) {
224	          an<RadioGroup> group;
225	          if (option.option_index == 0) {
226	            group = New<RadioGroup>(context, switcher);
227	            groups.push_back(group);
228	          } else {
229	            group = groups.back();
230	          }
231	          Append(group->CreateOption(option, option.option_index));
232	        }
233	        return Switches::kContinue;
234	      });
235	  for (auto& group : groups) {
236	    group->SelectOption(group->GetSelectedOption());
237	  }
238	  if (switcher->context()->get_option("_fold_options")) {
239	    auto folded_options = New<FoldedOptions>(switcher->schema()->config());
240	    switches.FindOption(
241	        [context, &folded_options](
242	            Switches::SwitchOption option) -> Switches::FindResult {
243	          bool current_state = context->get_option(option.option_name);
244	          if (option.type == Switches::kToggleOption) {
245	            if (has_state_label(option, current_state)) {
246	              folded_options->Append(option, current_state);
247	            }
248	          } else if (option.type == Switches::kRadioGroup) {
249	            if (current_state && has_state_label(option, option.option_index)) {
250	              folded_options->Append(option, option.option_index);
251	            }
252	          }
253	          return Switches::kContinue;
254	        });
255	    if (folded_options->size() > 1) {
256	      folded_options->Finish();
257	      candies_.clear();
258	      Append(folded_options);
259	    }
260	  }
261	  DLOG(INFO) << "num switches: " << candies_.size();
262	}
