23	void PunctConfig::LoadConfig(Engine* engine, bool load_symbols) {
24	  bool full_shape = engine->context()->get_option("full_shape");
25	  string shape(full_shape ? "full_shape" : "half_shape");
26	  if (shape_ == shape)
27	    return;
28	  shape_ = shape;
29	  Config* config = engine->schema()->config();
30	  mapping_ = config->GetMap("punctuator/" + shape);
31	  if (!mapping_) {
32	    LOG(WARNING) << "missing punctuation mapping.";
33	  }
34	  if (load_symbols) {
35	    symbols_ = config->GetMap("punctuator/symbols");
36	  }
37	  {
38	    string configured;
39	    if (config->GetString("punctuator/digit_separators", &configured)) {
40	      digit_separators_ = configured;
41	    }
42	  }
43	  {
44	    string configured;
45	    if (config->GetString("punctuator/digit_separator_action", &configured)) {
46	      digit_separator_commit_ = (configured == "commit");
47	    }
48	  }
