51	an<ConfigItem> PunctConfig::GetPunctDefinition(const string key) {
52	  an<ConfigItem> result = mapping_ ? mapping_->Get(key) : nullptr;
53	  return result ? result : symbols_ ? symbols_->Get(key) : nullptr;
54	}
