56	Punctuator::Punctuator(const Ticket& ticket) : Processor(ticket) {
57	  Config* config = engine_->schema()->config();
58	  if (config) {
59	    config->GetBool("punctuator/use_space", &use_space_);
60	  }
61	  config_.LoadConfig(engine_);
62	}
63	
64	static bool punctuation_is_translated(Context* ctx, const string& tag) {
65	  Composition& comp = ctx->composition();
66	  if (comp.empty() || !comp.back().HasTag(tag)) {
67	    return false;
68	  }
69	  auto cand = comp.back().GetSelectedCandidate();
70	  return cand && cand->type() == "punct";
71	}
72	
73	inline static bool ends_with_digit(const string& text) {
74	  auto len = text.length();
75	  return len > 0 && isdigit(text[len - 1]);
76	}
77	
78	// recognizes patterns like 3.14 12:30 1,000 1'000
79	static bool is_after_number(Context* ctx) {
80	  const CommitHistory& history = ctx->commit_history();
81	  if (history.empty()) {
82	    return false;
83	  }
84	  const CommitRecord& cr = history.back();
85	  return ends_with_digit(cr.text) & (cr.type == "thru" || cr.type == "raw");
86	}
87	
88	static bool is_after_digit_separator(Context* ctx) {
89	  const auto& comp = ctx->composition();
90	  return !comp.empty() && comp[0].HasTag("punct_number") &&
91	         comp[0].length == ctx->input().length();
92	}
93	
94	ProcessResult Punctuator::ProcessKeyEvent(const KeyEvent& key_event) {
95	  if (key_event.release() || key_event.ctrl() || key_event.alt() ||
96	      key_event.super())
97	    return kNoop;
98	  int ch = key_event.keycode();
99	  if (ch < 0x20 || ch >= 0x7f)
100	    return kNoop;
101	  Context* ctx = engine_->context();
102	  if (ctx->get_option("ascii_punct")) {
103	    return kNoop;
104	  }
105	  if ((isdigit(ch) || ch == XK_space) && is_after_digit_separator(ctx)) {
106	    // pushing ch directly may cause ch to be translated
107	    auto& comp = ctx->composition();
108	    string s = ctx->input().substr(comp[0].start, comp[0].end) + char(ch);
109	    ctx->AbortComposition();
110	    ctx->PushInput(s);
111	    ctx->Commit();
112	    return kAccepted;
113	  }
114	  if (!use_space_ && ch == XK_space && ctx->IsComposing()) {
115	    return kNoop;
116	  }
117	  if (ConvertDigitSeparator(ch)) {
118	    return kAccepted;
119	  }
120	  // sync with full_shape option
121	  config_.LoadConfig(engine_);
122	  string key(1, ch);
123	  auto punct_definition = config_.GetPunctDefinition(key);
124	  if (!punct_definition)
125	    return kNoop;
126	  DLOG(INFO) << "punct key: '" << key << "'";
127	  if (AlternatePunct(key, punct_definition)) {
128	    return kAccepted;
129	  }
130	  if (ReconvertDigitSeparatorAsPunct(key) || ctx->PushInput(ch)) {
131	    if (punctuation_is_translated(ctx, "punct")) {
132	      ConfirmUniquePunct(punct_definition) ||
133	          AutoCommitPunct(punct_definition) || PairPunct(punct_definition);
134	    }
135	  }
136	  return kAccepted;
137	}
138	
139	bool Punctuator::ConvertDigitSeparator(char ch) {
140	  if (!config_.is_digit_separator(ch)) {
141	    return false;
142	  }
143	  Context* ctx = engine_->context();
144	  if (ctx->composition().empty() && is_after_number(ctx)) {
145	    DLOG(INFO) << "convert punct in number: " << ch;
146	    ctx->PushInput(ch) && punctuation_is_translated(ctx, "punct_number") &&
147	        (config_.digit_separator_commit() ? ctx->Commit()
148	                                          : ctx->composition().Forward());
149	    return true;
150	  }
151	  return false;
152	}
153	
154	bool Punctuator::ReconvertDigitSeparatorAsPunct(const string& key) {
155	  if (!config_.has_digit_separators()) {
156	    return false;
157	  }
158	  Context* ctx = engine_->context();
159	  // repeat the same punctuation key to access the original binding
160	  if (ctx->input() != key) {
161	    return false;
162	  }
163	  Composition& comp = ctx->composition();
164	  if (!comp.empty()) {
165	    Segment& segment = comp[0];
166	    if (segment.HasTag("punct_number")) {
167	      segment.tags.erase("punct_number");
168	      segment.tags.insert("punct");
169	      segment.status = Segment::kVoid;
170	      DLOG(INFO) << "reconvert punct, key = " << key;
171	      ctx->ReopenPreviousSegment();
172	      return true;
173	    }
174	  }
175	  return false;
176	}
