178	bool Punctuator::AlternatePunct(const string& key,
179	                                const an<ConfigItem>& definition) {
180	  if (!As<ConfigList>(definition))
181	    return false;
182	  Context* ctx = engine_->context();
183	  Composition& comp = ctx->composition();
184	  if (comp.empty())
185	    return false;
186	  Segment& segment(comp.back());
187	  if (segment.status > Segment::kVoid && segment.HasTag("punct") &&
188	      key == ctx->input().substr(segment.start, segment.end - segment.start)) {
189	    if (!segment.menu ||
190	        segment.menu->Prepare(segment.selected_index + 2) == 0) {
191	      LOG(ERROR) << "missing candidate for punctuation '" << key << "'.";
192	      return false;
193	    }
194	    DLOG(INFO) << "alternating punctuation '" << key << "'.";
195	    (segment.selected_index += 1) %= segment.menu->candidate_count();
196	    segment.status = Segment::kGuess;
197	    return true;
198	  }
199	  return false;
200	}
