284	an<Candidate> CreatePunctCandidate(const string& punct,
285	                                   const Segment& segment) {
286	  const char half_shape[] =
287	      "\xe3\x80\x94\xe5\x8d\x8a\xe8\xa7\x92\xe3\x80\x95";  // 〔半角〕
288	  const char full_shape[] =
289	      "\xe3\x80\x94\xe5\x85\xa8\xe8\xa7\x92\xe3\x80\x95";  // 〔全角〕
290	  bool is_half_shape = false;
291	  bool is_full_shape = false;
292	  const char* p = punct.c_str();
293	  uint32_t ch = utf8::unchecked::next(p);
294	  if (*p == '\0') {  // length == 1 unicode character
295	    bool is_ascii = (ch >= 0x20 && ch < 0x7F);
296	    bool is_ideographic_space = (ch == 0x3000);
297	    bool is_full_shape_ascii = (ch >= 0xFF01 && ch <= 0xFF5E);
298	    bool is_kana =
299	        ((ch >= 0x30A1 && ch <= 0x30FC) || ch == 0x3001 || ch == 0x3002 ||
300	         ch == 0x300C || ch == 0x300D || ch == 0x309B || ch == 0x309C);
301	    bool is_half_shape_kana = (ch >= 0xFF61 && ch <= 0xFF9F);
302	    bool is_hangul = (ch >= 0x3131 && ch <= 0x3164);
303	    bool is_half_shape_hangul = (ch >= 0xFFA0 && ch <= 0xFFDC);
304	    bool is_full_shape_narrow_symbol =
305	        (ch == 0xFF5F || ch == 0xFF60 || (ch >= 0xFFE0 && ch <= 0xFFE6));
306	    bool is_narrow_symbol =
307	        (ch == 0x00A2 || ch == 0x00A3 || ch == 0x00A5 || ch == 0x00A6 ||
308	         ch == 0x00AC || ch == 0x00AF || ch == 0x2985 || ch == 0x2986);
309	    bool is_half_shape_wide_symbol = (ch >= 0xFFE8 && ch <= 0xFFEE);
310	    bool is_wide_symbol = ((ch >= 0x2190 && ch <= 0x2193) || ch == 0x2502 ||
311	                           ch == 0x25A0 || ch == 0x25CB);
312	    is_half_shape = is_ascii || is_half_shape_kana || is_half_shape_hangul ||
313	                    is_narrow_symbol || is_half_shape_wide_symbol;
314	    is_full_shape = is_ideographic_space || is_full_shape_ascii || is_kana ||
315	                    is_hangul || is_full_shape_narrow_symbol || is_wide_symbol;
316	  }
317	  bool one_key = (segment.end - segment.start == 1);
318	  return New<SimpleCandidate>("punct", segment.start, segment.end, punct,
319	                              (is_half_shape   ? half_shape
320	                               : is_full_shape ? full_shape
321	                                               : ""),
322	                              one_key ? punct : "");
323	}
324	
325	an<Translation> PunctTranslator::Query(const string& input,
326	                                       const Segment& segment) {
327	  if (segment.HasTag("punct_number")) {
328	    if (!input.empty()) {
329	      string punct = input;
330	      formatter_.Format(&punct);
331	      return New<UniqueTranslation>(CreatePunctCandidate(punct, segment));
332	    }
333	    return nullptr;
334	  }
335	  if (!segment.HasTag("punct"))
336	    return nullptr;
337	  // sync with full_shape option
338	  config_.LoadConfig(engine_);
339	  auto definition = config_.GetPunctDefinition(input);
340	  if (!definition)
341	    return nullptr;
342	  DLOG(INFO) << "populating punctuation candidates for '" << input << "'.";
343	  auto translation =
344	      TranslateUniquePunct(input, segment, As<ConfigValue>(definition));
345	  if (!translation)
346	    translation =
347	        TranslateAlternatingPunct(input, segment, As<ConfigList>(definition));
348	  if (!translation)
349	    translation =
350	        TranslateAutoCommitPunct(input, segment, As<ConfigMap>(definition));
351	  if (!translation)
352	    translation =
353	        TranslatePairedPunct(input, segment, As<ConfigMap>(definition));
354	  // if (translation) {
355	  //   const char tips[] =
356	  //       "\xe3\x80\x94\xe7\xac\xa6\xe8\x99\x9f\xe3\x80\x95";  // 〔符號〕
357	  //   const_cast<Segment*>(&segment)->prompt = tips;
358	  // }
359	  return translation;
360	}
361	
362	an<Translation> PunctTranslator::TranslateUniquePunct(
363	    const string& key,
364	    const Segment& segment,
365	    const an<ConfigValue>& definition) {
366	  if (!definition)
367	    return nullptr;
368	  return New<UniqueTranslation>(
369	      CreatePunctCandidate(definition->str(), segment));
370	}
371	
372	an<Translation> PunctTranslator::TranslateAlternatingPunct(
373	    const string& key,
374	    const Segment& segment,
375	    const an<ConfigList>& definition) {
376	  if (!definition)
377	    return nullptr;
378	  auto translation = New<FifoTranslation>();
379	  for (size_t i = 0; i < definition->size(); ++i) {
380	    auto value = definition->GetValueAt(i);
381	    if (!value) {
382	      LOG(WARNING) << "invalid alternating punct at index " << i << " for '"
383	                   << key << "'.";
384	      continue;
385	    }
386	    translation->Append(CreatePunctCandidate(value->str(), segment));
387	  }
388	  if (!translation->size()) {
389	    LOG(WARNING) << "empty candidate list for alternating punct '" << key
390	                 << "'.";
391	    translation.reset();
392	  }
393	  return translation;
394	}
395	
396	an<Translation> PunctTranslator::TranslateAutoCommitPunct(
397	    const string& key,
398	    const Segment& segment,
399	    const an<ConfigMap>& definition) {
400	  if (!definition || !definition->HasKey("commit"))
401	    return nullptr;
402	  auto value = definition->GetValue("commit");
403	  if (!value) {
404	    LOG(WARNING) << "unrecognized punct definition for '" << key << "'.";
405	    return nullptr;
406	  }
407	  return New<UniqueTranslation>(CreatePunctCandidate(value->str(), segment));
408	}
409	
410	an<Translation> PunctTranslator::TranslatePairedPunct(
411	    const string& key,
412	    const Segment& segment,
413	    const an<ConfigMap>& definition) {
414	  if (!definition || !definition->HasKey("pair"))
415	    return nullptr;
416	  auto list = As<ConfigList>(definition->Get("pair"));
417	  if (!list || list->size() != 2) {
418	    LOG(WARNING) << "unrecognized pair definition for '" << key << "'.";
419	    return nullptr;
420	  }
421	  auto translation = New<FifoTranslation>();
422	  for (size_t i = 0; i < list->size(); ++i) {
423	    auto value = list->GetValueAt(i);
424	    if (!value) {
425	      LOG(WARNING) << "invalid paired punct at index " << i << " for '" << key
426	                   << "'.";
427	      continue;
428	    }
429	    translation->Append(CreatePunctCandidate(value->str(), segment));
430	  }
431	  if (translation->size() != 2) {
432	    LOG(WARNING) << "invalid num of candidate for paired punct '" << key
433	                 << "'.";
434	    translation.reset();
435	  }
436	  return translation;
437	}
