19	bool Patterns::Load(an<ConfigList> patterns) {
20	  clear();
21	  if (!patterns)
22	    return false;
23	  for (auto it = patterns->begin(); it != patterns->end(); ++it) {
24	    if (auto value = As<ConfigValue>(*it)) {
25	      push_back(boost::regex(value->str()));
26	    }
27	  }
28	  return true;
29	}
