33	void Spans::AddVertex(size_t vertex) {
34	  if (vertices_.empty() || vertices_.back() < vertex) {
35	    vertices_.push_back(vertex);
36	    return;
37	  }
38	  auto lb = std::lower_bound(vertices_.begin(), vertices_.end(), vertex);
39	  if (*lb != vertex) {
40	    vertices_.insert(lb, vertex);
41	  }
42	}
43	
44	void Spans::AddSpan(size_t start, size_t end) {
45	  AddVertex(start);
46	  AddVertex(end);
47	}
48	
49	void Spans::AddSpans(const Spans& spans) {
50	  for (auto vertex : spans.vertices_) {
51	    AddVertex(vertex);
52	  }
53	}
54	
55	void Spans::Clear() {
56	  vertices_.clear();
57	}
58	
59	size_t Spans::PreviousStop(size_t caret_pos) const {
60	  for (auto x : boost::adaptors::reverse(vertices_)) {
61	    if (x < caret_pos)
62	      return x;
63	  }
64	  return caret_pos;
65	}
66	
67	size_t Spans::NextStop(size_t caret_pos) const {
68	  for (auto x : vertices_) {
69	    if (x > caret_pos)
70	      return x;
71	  }
72	  return caret_pos;
